local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("anim", function(inst, time, anim, fn, clean, notIdle)     if not inst or not time then         return     end     inst:DoTaskInTime(time, function()         if inst and anim and TD.live(inst) then             inst.AnimState:PlayAnimation(anim)         end         if fn then             fn()         end         if clean then             if inst.Physics.ClearMotorVelOverride then                 inst.Physics:ClearMotorVelOverride()             end             if not notIdle and inst.sg and inst.sg.sg and inst.sg.sg.states and inst.sg.sg.states.idle then                 TD.goto(inst, "idle")             end             if not notIdle and inst.components.playercontroller then                 inst.components.playercontroller:Enable(true)             end         end     end) end) TD.createFn("goto", function(v, frame, ...)     if v and v.sg and v.sg.sg and v.sg.sg.states and v.sg.sg.states[frame] and TD.live(v) then         if v.HasTag and v:HasTag("player") and not TD.live(v) then             return         end         v.sg:GoToState(frame, ...)     end end) TD.createFn("goSG", function(inst, anim, x, z)     TD.server(function()         if x and z then             local param = {}             param.anim = anim             param.x = x             param.z = z             TD.mgn(inst):server_send(TD.holder("%s_goto_and_play"), param, true)             TD.goto(inst, param.anim, Vector3(param.x or 0, 0, param.z or 0))         else             local param = {}             param.anim = anim             TD.mgn(inst):server_send(TD.holder("%s_goto_and_play"), param, true)             TD.goto(inst, param.anim)         end     end) end) TD.createFn("lightOnlyDayInventory", function(inst, r, g, b)     if not inst or not TD.server() then         return     end     r = r or 245 / 85     g = g or r     b = b or r     if not inst.Light then         inst.entity:AddLight()         inst.Light:SetRadius(6)         inst.Light:SetFalloff(.5)         inst.Light:SetIntensity(0.9)         inst.Light:EnableClientModulation(true)     end          TD.latter(inst, 0, function()         local function OnIsDay(inst)             if not (TD.GetWorld() and TD.GetWorld().state) and TD.GetWorld().HasTag then                 return             end             local isday = TD.GetWorld().state.isday                          if isday and not TD.GetWorld():HasTag("cave") then                 TD.lightOff(inst)             elseif TD.dropOrHand(inst) then                                  TD.lightOn(inst, r, g, b)             else                 TD.lightOff(inst)             end         end         inst:WatchWorldState("isday", OnIsDay)         if TD.GetWorld() and TD.GetWorld().state then             OnIsDay(inst)         end         inst:ListenForEvent("onputininventory", function(inst)             TD.latter(inst, 0, function()                 OnIsDay(inst)             end)         end)         inst:ListenForEvent("ondropped", function(inst)             TD.latter(inst, 0, function()                 OnIsDay(inst)             end)         end)     end)     return inst.Light end) TD.createFn("lightOnlyDay", function(inst, r, g, b)     if not inst or not TD.server() then         return     end     r = r or 245 / 85     g = g or r     b = b or r     if not inst.Light then         inst.entity:AddLight()         inst.Light:SetRadius(6)         inst.Light:SetFalloff(.5)         inst.Light:SetIntensity(0.9)         inst.Light:EnableClientModulation(true)     end          TD.latter(inst, 0, function()         local function OnIsDay(inst)             if not (TD.GetWorld() and TD.GetWorld().state) and TD.GetWorld().HasTag then                 return             end             local isday = TD.GetWorld().state.isday             if isday and not TD.GetWorld():HasTag("cave") then                 TD.lightOff(inst)             else                 TD.lightOn(inst, r, g, b)             end         end         inst:WatchWorldState("isday", OnIsDay)         if TD.GetWorld() and TD.GetWorld().state then             OnIsDay(inst)         end     end)     return inst.Light end) TD.createFn("lightOn", function(inst, r, g, b)     if not inst or inst.td1madao_light_fx then         return     end     inst.td1madao_light_fx = TD.spawn("nightstickfire")     inst.td1madao_light_fx.entity:AddFollower()     inst.td1madao_light_fx.Follower:FollowSymbol(inst.GUID, "swap_object", 0, -110, 0)     return inst.td1madao_light_fx end) TD.createFn("lightOff", function(inst)     if not inst or not inst.td1madao_light_fx then         return     end     TD.removeElem(inst,"td1madao_light_fx") end) TD.createFn("color", function(item, r, g, b,a)     if not item or not r then         return     end     g = g or r     b = b or r     if item and item.AnimState and item.AnimState.SetMultColour then         item.AnimState:SetMultColour(r, g, b, a or 1)     else         TD.addC(item, "highlight", function(comp)             comp:SetAddColour(Vector3(r, g, b))         end)     end     return item end) TD.createFn("scale", function(v, x, y, z)     if v and v.Transform and v.Transform.SetScale and TD.isPos(x) then         if not TD.isPos(y) then             y = x         end         if not TD.isPos(z) then             z = x         end         v.Transform:SetScale(x, y, z)     end     return v end) TD.createFn("sg", function(state)     if not state then         return     end     TD.server(function()         AddStategraphState("wilson", state)     end) end) 